def modular_square_root(a, p):
    """Sử dụng thuật toán Tonelli-Shanks để tìm căn bậc hai modulo p cho trường hợp p % 4 == 1."""
    if pow(a, (p - 1) // 2, p) != 1: return None
    s, q = 0, p - 1
    while q % 2 == 0: s += 1; q //= 2
    if s == 1: return pow(a, (p + 1) // 4, p)
    z = 2
    while pow(z, (p - 1) // 2, p) != p - 1: z += 1
    c, r, t, m = pow(z, q, p), pow(a, (q + 1) // 2, p), pow(a, q, p), s
    while t != 1:
        temp, i = t, 0
        for i in range(1, m):
            temp = pow(temp, 2, p)
            if temp == 1: break
        b = pow(c, 2**(m - i - 1), p)
        r, t, c, m = (r * b) % p, (t * b * b) % p, (b * b) % p, i
    return r

